import functools

def log(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        print(f'calling {func.__name__}')
        return func(*args, **kwargs)
    return wrapper

def validate(func):
    @functools.wraps(func)
    def wrapper(x):
        if x < 0:
            raise ValueError('negative')
        return func(x)
    return wrapper

@log
@validate
