Given this code that uses a descriptor with __set_name__ and a metaclass:

class Tracked:
    def __set_name__(self, owner, name):
        self.public_name = name
        self.private_name = f'_{name}'

    def __get__(self, obj, objtype=None):
        return getattr(obj, self.private_name, 'unset')

    def __set__(self, obj, value):
        setattr(obj, self.private_name, value)
        obj._changes.append(self.public_name)

class ChangeTracker(type):
    def __call__(cls, *args, **kwargs):
        instance = super().__call__(*args, **kwargs)
        instance._changes = []
        return instance

class Model(metaclass=ChangeTracker):
    name = Tracked()
    age = Tracked()

m = Model()
m.name = 'Alice'
m.age = 30
m.name = 'Bob'
print(m._changes)

