Consider this testing pattern for a function with complex dependencies:

class PaymentProcessor:
    def __init__(self, gateway, notifier, audit_log):
        self.gateway = gateway
        self.notifier = notifier
        self.audit_log = audit_log

    def process(self, amount: float, user_id: int) -> dict:
        if amount <= 0:
            raise ValueError('Amount must be positive')
        charge = self.gateway.charge(user_id, amount)
        if charge['status'] == 'success':
            self.notifier.send(user_id, f'Charged ${amount}')
            self.audit_log.record('charge', user_id, amount)
        return charge

def test_successful_payment():
    gateway = Mock()
    gateway.charge.return_value = {'status': 'success', 'id': 'tx_123'}
    notifier = Mock()
    audit = Mock()

    processor = PaymentProcessor(gateway, notifier, audit)
    result = processor.process(50.0, 42)

    assert result == {'status': 'success', 'id': 'tx_123'}
    gateway.charge.assert_called_once_with(42, 50.0)
    notifier.send.assert_called_once_with(42, 'Charged $50.0')
    audit.record.assert_called_once_with('charge', 42, 50.0)

What testing principle does this test violate, and why is it fragile?

Consider this context manager implementation:

from contextlib import asynccontextmanager
import asyncio

class ConnectionPool:
    def __init__(self, max_size=5):
        self._pool = asyncio.Queue(maxsize=max_size)
        self._size = 0
        self._max_size = max_size
        self._lock = asyncio.Lock()

    @asynccontextmanager
    async def acquire(self):
        conn = None
        try:
            conn = self._pool.get_nowait()
        except asyncio.QueueEmpty:
            async with self._lock:
                if self._size < self._max_size:
                    conn = await self._create_connection()
                    self._size += 1
            if conn is None:
                conn = await self._pool.get()  # block until available
        try:
            yield conn
        finally:
            await self._pool.put(conn)

