You need to safely handle user-uploaded JSON that may contain deeply nested structures. Consider:

import json

def safe_parse(raw: str, max_depth: int = 20) -> dict:
    def check_depth(obj, depth=0):
        if depth > max_depth:
            raise ValueError(f'Nesting exceeds {max_depth} levels')
        if isinstance(obj, dict):
            for v in obj.values():
                check_depth(v, depth + 1)
        elif isinstance(obj, list):
            for item in obj:
                check_depth(item, depth + 1)

    parsed = json.loads(raw)
    check_depth(parsed)
    return parsed

